export const checkId = 'database-config';
export const name = 'Database Configuration';
export const appliesTo = ['deployable', 'server', 'framework'];

const DB_DEPS = [
  'mongoose', 'sequelize', 'prisma', '@prisma/client', 'typeorm', 'knex',
  'drizzle-orm', 'drizzle-kit', 'kysely', '@astrojs/db', 'objection', 'bookshelf',
  'mikro-orm', '@mikro-orm/core', 'slonik', 'zapatos', '@databases/pg',
  'pg', 'postgres', 'mysql2', 'mysql', 'mongodb', 'redis', 'ioredis',
  '@upstash/redis', '@upstash/postgres', '@planetscale/database', '@vercel/postgres',
  '@vercel/kv', '@neondatabase/serverless', 'neon', '@libsql/client', 'libsql',
  'better-sqlite3', 'sqlite3', 'sql.js', 'turso', 'bun-sql',
  'tedious', 'oracledb', 'firebase', '@google-cloud/firestore',
  'dexie', 'pouchdb', 'rxdb', 'denodb', 'dgraph-js', 'faunadb',
];

const DB_DEP_SUBSTRINGS = [
  'drizzle', 'prisma', 'planetscale', 'neon', 'libsql', 'turso', 'upstash',
  'astrojs/db', 'supabase', 'kysely', 'firebase', 'fauna',
];

const GOOD_PATTERNS = [
  /(?:process\.env|Bun\.env|import\.meta\.env)\.[A-Z_]*(?:DATABASE|DB|POSTGRES|POSTGRESQL|MONGO|MONGODB|REDIS|SQLITE|TURSO|LIBSQL|PLANETSCALE|NEON|D1|UPSTASH|ASTRO_DB|ASTRO_DATABASE|DIRECT_URL|SHADOW_DATABASE)[A-Z_]*/i,
  /Deno\.env\.get\s*\(\s*["'][^"']*(?:DATABASE|DB|POSTGRES|MONGO|REDIS|SQLITE|TURSO|LIBSQL|PLANETSCALE|NEON|D1|ASTRO_DATABASE)[^"']*["']\s*\)/i,
  /env\s*\(\s*["'][^"']*(?:DATABASE|DB|POSTGRES|MONGO|REDIS|SQLITE|TURSO|LIBSQL|PLANETSCALE|NEON|D1)[^"']*["']\s*\)/i,
  /env\.[A-Z_]*(?:DATABASE|DB|POSTGRES|MONGO|REDIS|SQLITE|TURSO|LIBSQL|PLANETSCALE|NEON|D1|UPSTASH|ASTRO_DATABASE)[A-Z_]*/i,
  /\$\{(?:DATABASE|DB|POSTGRES|MONGO|REDIS|SQLITE|TURSO|LIBSQL|PLANETSCALE|NEON|D1|ASTRO_DATABASE)[A-Z_]*\}/i,
  /^(?:DATABASE|DB|POSTGRES|MONGO|MONGODB|REDIS|SQLITE|TURSO|LIBSQL|PLANETSCALE|NEON|D1|UPSTASH|ASTRO_DB|ASTRO_DATABASE)[A-Z_]*=/im,
  /binding\s*=\s*["']DB["']/i,
  /\[\[\s*(?:d1_databases|env\.[a-z]+\.d1_databases)\s*\]\]/im,
  /process\.env\s*\[\s*["'][^"']*(?:DATABASE|DB)[^"']*["']\s*\]/i,
];

const BAD_PATTERNS = [
  /(?:mongodb|mongodb\+srv|postgres|postgresql|mysql|redis):\/\/[^:]+:[^@\s]+@\S+/i,
  /mysql:\/\/\w+:\w+@\w+/i,
  /postgres(?:ql)?:\/\/\w+:[^@\s]+@\w+/i,
];

const EXCLUDE_PATH_RE = /\/(?:node_modules|\.git|dist|build|coverage|\.next|\.nuxt|\.astro|out|tmp|temp|vendor)\//;
const EXAMPLE_LIKE_RE = /(^|[\/])(example|examples|template|templates|demo|demos|playground|playgrounds|test|tests|e2e|__tests__|fixtures|fixture|benchmark|benchmarks|script|scripts)[\/]/i;

function isDbDriverLibrary(name) {
  if (!name) return false;
  if (DB_DEPS.includes(name)) return true;
  if (name.startsWith('@')) {
    const base = name.split('/')[1];
    if (base && DB_DEPS.includes(base)) return true;
  }
  return false;
}

function hasDbDepInManifest(text) {
  try {
    const pkg = JSON.parse(text);
    const allDeps = { ...pkg.dependencies, ...pkg.devDependencies, ...pkg.peerDependencies };
    const keys = Object.keys(allDeps);
    if (keys.some(k => DB_DEPS.includes(k))) return true;
    if (keys.some(k => DB_DEP_SUBSTRINGS.some(s => k.includes(s)))) return true;
  } catch {
    // ignore JSON parse errors
  }
  return false;
}

export async function check(context) {
  const { tree, files, packageJson } = context;

  try {
    if (tree.length === 0) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Empty repo — no DB config needed', findings: [] };
    }

    if (isDbDriverLibrary(packageJson?.name)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: `DB driver/library (${packageJson.name}) — not applicable`, findings: [] };
    }

    const manifestPaths = [];
    const strongArtifacts = [];
    const envPaths = [];

    for (const p of tree) {
      if (EXCLUDE_PATH_RE.test(p)) continue;
      if (EXAMPLE_LIKE_RE.test(p)) continue;

      if (/(^|[\/])package\.json$/.test(p)) {
        manifestPaths.push(p);
      } else if (/\.prisma$/.test(p)) {
        strongArtifacts.push({ path: p, type: 'prisma' });
      } else if (/(^|[\/])drizzle\.config\.[^\/]*$/.test(p)) {
        strongArtifacts.push({ path: p, type: 'drizzle' });
      } else if (/(^|[\/])db\/config\.(ts|js|mjs|cjs)$/.test(p)) {
        strongArtifacts.push({ path: p, type: 'astro-db' });
      } else if (/(^|[\/])wrangler\.toml$/.test(p)) {
        strongArtifacts.push({ path: p, type: 'wrangler' });
      } else if (/docker-compose[^\/]*\.ya?ml$/i.test(p)) {
        strongArtifacts.push({ path: p, type: 'docker' });
      } else if (/(^|[\/])\.env/.test(p)) {
        envPaths.push(p);
      }
    }

    let hasDbDep = false;
    for (const p of manifestPaths.slice(0, 50)) {
      const content = await files.get(p);
      if (content && hasDbDepInManifest(content)) {
        hasDbDep = true;
        break;
      }
    }

    if (!hasDbDep && strongArtifacts.length === 0) {
      return { checkId, status: 'not-applicable', confidence: 'medium', message: 'No database dependency or DB-related files found', findings: [] };
    }

    const scanSet = new Set();

    for (const p of envPaths.slice(0, 20)) scanSet.add(p);
    for (const a of strongArtifacts.slice(0, 20)) scanSet.add(a.path);

    for (const p of tree) {
      if (scanSet.size >= 60) break;
      if (EXCLUDE_PATH_RE.test(p) || EXAMPLE_LIKE_RE.test(p)) continue;
      if (!/\.(js|ts|mjs|cjs)$/.test(p)) continue;
      if (/(^|[\/])(db|database|drizzle|prisma|models)[\/]/i.test(p)) {
        scanSet.add(p);
      }
    }

    for (const p of tree) {
      if (scanSet.size >= 75) break;
      if (EXCLUDE_PATH_RE.test(p) || EXAMPLE_LIKE_RE.test(p)) continue;
      if (!/\.(js|ts|mjs|cjs)$/.test(p)) continue;
      if (/(^|[\/])(db|database|connection|client|schema)\.(js|ts|mjs|cjs)$/i.test(p)) {
        scanSet.add(p);
      }
    }

    const sourceFiles = Array.from(scanSet).slice(0, 80);

    let foundGood = false;
    let foundBad = false;
    const findings = [];

    function addFinding(file, line, issue) {
      if (findings.length >= 15) return;
      const f = { file, issue };
      if (line != null) f.line = line;
      findings.push(f);
    }

    for (const filePath of sourceFiles) {
      const content = await files.get(filePath);
      if (!content) continue;

      for (const pattern of GOOD_PATTERNS) {
        if (!pattern.test(content)) continue;
        foundGood = true;
        const lines = content.split('\n');
        let added = false;
        for (let i = 0; i < lines.length && i < 600; i++) {
          if (pattern.test(lines[i])) {
            addFinding(filePath, i + 1, 'DB config uses environment variables');
            added = true;
            break;
          }
        }
        if (!added) addFinding(filePath, undefined, 'DB config uses environment variables');
      }

      const isEnvTemplate = /(^|[\/])\.env\./.test(filePath);
      const isDockerCompose = /docker-compose/.test(filePath);
      if (!isEnvTemplate && !isDockerCompose) {
        for (const pattern of BAD_PATTERNS) {
          const re = new RegExp(pattern.source, 'gmi');
          let match;
          let count = 0;
          while ((match = re.exec(content)) !== null && count < 2) {
            count++;
            foundBad = true;
            const snippet = match[0].substring(0, 40);
            const lines = content.split('\n');
            let added = false;
            for (let i = 0; i < lines.length && i < 600; i++) {
              if (lines[i].includes(snippet)) {
                addFinding(filePath, i + 1, 'Hardcoded DB connection string with credentials');
                added = true;
                break;
              }
            }
            if (!added) addFinding(filePath, undefined, 'Hardcoded DB connection string with credentials');
          }
        }
      }
    }

    if (foundBad) {
      return { checkId, status: 'fail', confidence: 'high', message: 'Hardcoded DB credentials detected', findings };
    }
    if (foundGood) {
      return { checkId, status: 'pass', confidence: 'high', message: 'DB configured with environment variables', findings };
    }

    if (hasDbDep || strongArtifacts.length > 0) {
      if (findings.length === 0) {
        const target = strongArtifacts[0]?.path || manifestPaths[0] || 'package.json';
        addFinding(target, undefined, 'Database usage detected but env-based configuration not confirmed in committed files');
      }
      return { checkId, status: 'check-it', confidence: 'medium', message: 'Database usage detected but could not verify env-based configuration', findings };
    }

    return { checkId, status: 'not-applicable', confidence: 'medium', message: 'No database dependency or DB-related files found', findings: [] };
  } catch (err) {
    console.error(`[database-config] error:`, err);
    return { checkId, status: 'check-it', confidence: 'low', message: `Error: ${err.message}`, findings: [] };
  }
}
